// Solution
function Component({ name, age }) {
  const [state, setState] = useState({ name, age });
  const shouldMemoize = age >= state.age - 5 && age <= state.age + 5;
  const memoizedRender = useMemo(() => (
    <div>Hello, {name}!</div>
  ), [name, shouldMemoize]);
  return memoizedRender;
}
